def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

def main():
    import sys
    input = sys.stdin.read
    data = input().strip().split()

    nums = list(map(int, data[:-1]))
    target = int(data[-1])

    result = solve(nums, target)
    print(result)

if __name__ == "__main__":
    main()
